class DataProcessor {
public:
    double computeAverage(const std::string& filename) {
        std::ifstream inFile;
        inFile.open(filename);
        if (!inFile) {
            throw std::runtime_error("Could not open file");
        }

        int num;
        int sum = 0;
        int totalElements = 0;

        while (inFile >> num) {
            sum += num;
            totalElements++;
        }

        if (inFile.fail() && !inFile.eof()) {
            inFile.close();
            throw std::invalid_argument("Invalid non-integer value found");
        }

        inFile.close();

        if (totalElements == 0) {
            throw std::domain_error("File is empty");
        }

        return static_cast<double>(sum) / totalElements;
    }
};

