  real=r;
  imag=i;
 }

 ComplexNumber operator+(ComplexNumber c){
  return ComplexNumber(real+c.real,imag+c.imag);
 }

 ComplexNumber operator-(ComplexNumber c){
  return ComplexNumber(real-c.real,imag-c.imag);
 }

 bool operator==(ComplexNumber c){
  return real==c.imag;
 }
};

