bool isBalanced(const std::string& expression) {
    int roundCount = 0;
    int curlyCount = 0;
    int squareCount = 0;

    for (char ch : expression) {
        if (ch == '(') roundCount++;
        if (ch == ')') roundCount--;
        if (ch == '{') curlyCount++;
        if (ch == '}') curlyCount--;
        if (ch == '[') squareCount++;
        if (ch == ']') squareCount--;

        if (roundCount < 0 || curlyCount < 0 || squareCount < 0) return false;
    }

    return (roundCount == 0 && curlyCount == 0 && squareCount == 0);
}

