class IntArray {
private:
    int* data;
    size_t size;
public:
    IntArray(size_t s) {
        size = s;
        data = new int[size];
        for(size_t i = 0; i < size; ++i) data[i] = 0;
    }
    ~IntArray() {
        delete[] data;
    }
    IntArray(const IntArray& other) {
        size = other.size;
        data = new int[size];
        for(size_t i = 0; i < size; ++i) data[i] = other.data[i];
    }
    IntArray& operator=(const IntArray& other) {
        if (this != &other) {
            delete[] data;
            size = other.size;
            data = new int[size];
            for(size_t i = 0; i < size; ++i) data[i] = other.data[i];
        }
        return *this;
    }
    void set(size_t index, int value) {
        if (index >= 0 && index < size) data[index] = value;
        else std::cout << "Index out of bounds\n";
    }
    int get(size_t index) const {
        if (index >= 0 && index < size) return data[index];
        std::cout << "Index out of bounds\n";
        return -1;
    }
};

